INSERT INTO `letter_templates` VALUES (1,'Lettera di Assegnazione Arbitro','assignment','Assegnazione Arbitrale - {{tournament_name}}',NULL,'Gentile {{user_name}},\n\nCon la presente Le comunichiamo che è stato/a assegnato/a come {{assignment_role}} per il torneo:\n\n**{{tournament_name}}**\nData: {{tournament_date}}\nCircolo: {{club_name}}\n\nDettagli dell\'assegnazione:\n- Ruolo: {{assignment_role}}\n- Compenso: €{{fee_amount}}\n- Persona di contatto: {{contact_person}}\n\nLa preghiamo di confermare la Sua partecipazione entro 48 ore dalla ricezione di questa comunicazione.\n\nPer qualsiasi chiarimento, rimaniamo a Sua disposizione.\n\nCordiali saluti,\nComitato Organizzatore',NULL,NULL,1,0,'[\"user_name\", \"tournament_name\", \"tournament_date\", \"club_name\", \"assignment_role\", \"fee_amount\", \"contact_person\"]','2025-09-10 12:33:06','2025-09-10 12:33:06'),(2,'Conferma Disponibilità','club','Conferma Disponibilità - {{tournament_name}}',NULL,'Gentile {{user_name}},\n\nConfermiamo di aver ricevuto la Sua dichiarazione di disponibilità per il torneo:\n\n**{{tournament_name}}**\nStato: {{availability_status}}\n\nLe assegnazioni verranno comunicate dopo la scadenza del termine per le dichiarazioni di disponibilità ({{deadline_date}}).\n\nLa ringraziamo per la Sua collaborazione.\n\nCordiali saluti,\nSegreteria Tornei',NULL,NULL,1,0,'[\"user_name\", \"tournament_name\", \"availability_status\", \"deadline_date\"]','2025-09-10 12:33:06','2025-09-10 12:33:06'),(3,'Lettera di Convocazione','convocation','Convocazione Ufficiale - {{tournament_name}}',NULL,'Gentile {{user_name}},\n\nÈ convocato/a ufficialmente per prestare servizio nel torneo:\n\n**{{tournament_name}}**\nData: {{tournament_date}}\nCircolo: {{club_name}}\nOrario arrivo: {{arrival_time}}\n\nISTRUZIONI IMPORTANTI:\n- Abbigliamento: {{dress_code}}\n- {{special_instructions}}\n\nSi ricorda che la partecipazione è obbligatoria, salvo gravi e documentati impedimenti.\n\nCordiali saluti,\nDirezione Tecnica',NULL,NULL,1,0,'[\"user_name\", \"tournament_name\", \"tournament_date\", \"club_name\", \"arrival_time\", \"dress_code\", \"special_instructions\"]','2025-09-10 12:33:06','2025-09-10 12:33:06'),(4,'Reminder Scadenza','institutional','Reminder: Scadenza Disponibilità - {{tournament_name}}',NULL,'Gentile {{user_name}},\n\nLe ricordiamo che la scadenza per la dichiarazione di disponibilità per il torneo:\n\n**{{tournament_name}}**\n\nè fissata per il {{deadline_date}} alle ore {{deadline_time}}.\n\nSe non ha ancora provveduto, La invitiamo a dichiarare la Sua disponibilità accedendo al sistema.\n\nCordiali saluti,\nSistema Automatico',NULL,NULL,1,0,'[\"user_name\", \"tournament_name\", \"deadline_date\", \"deadline_time\"]','2025-09-10 12:33:06','2025-09-10 12:33:06'),(5,'Certificato di Partecipazione','institutional','Certificato di Partecipazione - {{tournament_name}}',NULL,'CERTIFICATO DI PARTECIPAZIONE\n\nSi certifica che\n\n**{{user_name}}**\n\nha prestato servizio come {{assignment_role}} nel torneo:\n\n**{{tournament_name}}**\nsvoltosi in data {{tournament_date}}\n\nIl presente certificato è rilasciato per gli usi consentiti dalla legge.\n\nData: {{certificate_date}}\n\n_____________________\nIl Direttore Tecnico',NULL,NULL,1,0,'[\"user_name\", \"tournament_name\", \"tournament_date\", \"assignment_role\", \"certificate_date\"]','2025-09-10 12:33:06','2025-09-10 12:33:06'),(6,'Report Post-Torneo','institutional','Report Arbitrale - {{tournament_name}}',NULL,'REPORT ARBITRALE\n\nArbitro: {{user_name}}\nTorneo: {{tournament_name}}\nData: {{tournament_date}}\n\nRIEPILOGO:\n- Numero incidenti: {{incidents_count}}\n- Valutazione complessiva: {{overall_rating}}\n\nNote aggiuntive:\n[Spazio per note dell\'arbitro]\n\nFirma dell\'arbitro: _____________________\n\nData compilazione: {{report_date}}',NULL,NULL,1,0,'[\"user_name\", \"tournament_name\", \"tournament_date\", \"incidents_count\", \"overall_rating\", \"report_date\"]','2025-09-10 12:33:06','2025-09-10 12:33:06'),(7,'Lettera di Annullamento','institutional','Annullamento Torneo - {{tournament_name}}',NULL,'Gentile {{user_name}},\n\nCon rammarico Le comunichiamo che il torneo:\n\n**{{tournament_name}}**\n\nè stato annullato per il seguente motivo:\n{{cancellation_reason}}\n\n{{alternative_date}}\n\nCi scusiamo per l\'inconveniente e La ringraziamo per la comprensione.\n\nCordiali saluti,\nComitato Organizzatore',NULL,NULL,1,0,'[\"user_name\", \"tournament_name\", \"cancellation_reason\", \"alternative_date\"]','2025-09-10 12:33:06','2025-09-10 12:33:06'),(8,'Convocazione Arbitro - Template Nazionale','convocation','Convocazione per {{tournament_name}}',NULL,'Gentile {{user_name}},\n\nLa informiamo che è stato convocato per svolgere il ruolo di {{assignment_role}} in occasione del torneo:\n\n**{{tournament_name}}**\nDate: {{tournament_dates}}\nCircolo: {{club_name}}\nZona: {{zone_name}}\n\nLa preghiamo di confermare la Sua disponibilità entro 48 ore dalla ricezione della presente.\n\nPer ulteriori informazioni può contattare la segreteria di zona.\n\nCordiali saluti,\nLa Segreteria',NULL,NULL,1,1,'[\"user_name\", \"tournament_name\", \"tournament_dates\", \"club_name\", \"assignment_role\", \"zone_name\"]','2025-09-10 12:33:06','2025-09-10 12:33:06'),(9,'Comunicazione Circolo - Arbitri Assegnati','club','Arbitri assegnati per {{tournament_name}}',NULL,'Gentile {{contact_person}},\n\nCon la presente comunichiamo gli arbitri assegnati per il torneo:\n\n**{{tournament_name}}**\nDate: {{tournament_dates}}\n\n**Arbitri assegnati ({{total_referees}}):**\n{{referee_list}}\n\nGli arbitri sono stati informati della loro assegnazione.\n\nCordiali saluti,\nLa Segreteria di Zona',NULL,NULL,1,1,'[\"tournament_name\", \"tournament_dates\", \"club_name\", \"referee_list\", \"total_referees\", \"contact_person\"]','2025-09-10 12:33:06','2025-09-10 12:33:06'),(10,'Notifica Assegnazione - Template Standard','assignment','Nuova assegnazione: {{tournament_name}}',NULL,'Gentile {{user_name}},\n\nLa informiamo di essere stato assegnato al seguente torneo:\n\n**{{tournament_name}}**\nDate: {{tournament_dates}}\nCircolo: {{club_name}}\nRuolo: {{assignment_role}}\nAssegnato da: {{assigned_by}}\n\n{{assignment_notes}}\n\nLa assegnazione è stata confermata automaticamente.\n\nCordiali saluti',NULL,NULL,1,1,'[\"user_name\", \"tournament_name\", \"tournament_dates\", \"club_name\", \"assignment_role\", \"assigned_by\", \"assignment_notes\"]','2025-09-10 12:33:06','2025-09-10 12:33:06'),(11,'Convocazione SZR1 - Personalizzata','convocation','Convocazione Zona SZR1 - {{tournament_name}}',NULL,'Gentile {{user_name}},\n\nA nome della SZR1, La convoco per il torneo:\n\n**{{tournament_name}}**\nDate: {{tournament_dates}}\nCircolo: {{club_name}}\nRuolo: {{assignment_role}}\n\nPer informazioni specifiche della zona, può contattare:\n{{zone_contact}}\n\nGrazie per la Sua disponibilità.\n\nCordiali saluti,\nLa Segreteria SZR1',1,NULL,1,0,'[\"user_name\", \"tournament_name\", \"tournament_dates\", \"club_name\", \"assignment_role\", \"zone_name\", \"zone_contact\"]','2025-09-10 12:33:06','2025-09-10 12:33:06'),(12,'Convocazione SZR2 - Personalizzata','convocation','Convocazione Zona SZR2 - {{tournament_name}}',NULL,'Gentile {{user_name}},\n\nA nome della SZR2, La convoco per il torneo:\n\n**{{tournament_name}}**\nDate: {{tournament_dates}}\nCircolo: {{club_name}}\nRuolo: {{assignment_role}}\n\nPer informazioni specifiche della zona, può contattare:\n{{zone_contact}}\n\nGrazie per la Sua disponibilità.\n\nCordiali saluti,\nLa Segreteria SZR2',2,NULL,1,0,'[\"user_name\", \"tournament_name\", \"tournament_dates\", \"club_name\", \"assignment_role\", \"zone_name\", \"zone_contact\"]','2025-09-10 12:33:06','2025-09-10 12:33:06'),(13,'Template Istituzionale - Reminder Default','institutional','Promemoria - {{tournament_name}}',NULL,'Gentile {{user_name}},\n\nQuesto è un promemoria automatico relativo al torneo:\n\n**{{tournament_name}}**\nDate: {{tournament_dates}}\nCircolo: {{club_name}}\nZona: {{zone_name}}\n\nSe ha domande o necessita di chiarimenti, può contattare la segreteria di zona.\n\nCordiali saluti,\nSistema Automatico FIG',NULL,NULL,1,1,'[\"user_name\", \"tournament_name\", \"tournament_dates\", \"club_name\", \"zone_name\"]','2025-09-10 12:33:06','2025-09-10 12:33:06');
/*!40000 ALTER TABLE `letter_templates` ENABLE KEYS */;
UNLOCK TABLES;

