INSERT INTO `notification_clauses` VALUES (1,'spese_medico','spese','Spese Servizio Medico','Il circolo organizzatore dovrà farsi carico delle spese per il servizio medico obbligatorio come da regolamento FIG. L\'importo stimato è di €300,00 per l\'intera durata della manifestazione.','club',1,1,'2025-10-07 15:53:58','2025-10-07 15:53:58',NULL),(2,'spese_viaggio','spese','Rimborso Spese Viaggio','Il circolo rimborserà agli arbitri le spese di viaggio secondo il tariffario FIG vigente (€0,35/km per utilizzo mezzo proprio). Il rimborso dovrà essere liquidato entro 30 giorni dalla conclusione della manifestazione.','club',1,2,'2025-10-07 15:53:58','2025-10-07 15:53:58',NULL),(3,'spese_vitto','spese','Vitto Incluso','Il circolo fornirà il vitto agli arbitri per l\'intera durata della manifestazione presso le strutture del circolo stesso. I pasti comprenderanno pranzo e cena per le giornate di gara.','club',1,3,'2025-10-07 15:53:58','2025-10-07 15:53:58',NULL),(4,'spese_alloggio','spese','Alloggio Fornito','Il circolo fornirà l\'alloggio agli arbitri presso strutture convenzionate. L\'alloggio comprenderà camera singola e prima colazione per le notti necessarie alla copertura della manifestazione.','club',1,4,'2025-10-07 15:53:58','2025-10-07 15:53:58',NULL),(5,'spese_nessuna','spese','Nessuna Spesa Aggiuntiva','Non sono previste spese aggiuntive a carico del circolo organizzatore oltre a quelle già stabilite dal regolamento federale.','club',1,5,'2025-10-07 15:53:58','2025-10-07 15:53:58',NULL),(6,'spese_pacchetto_completo','spese','Pacchetto Completo','Il circolo si farà carico di vitto, alloggio, servizio medico e rimborso spese viaggio per tutti gli arbitri designati. Tutti i servizi saranno forniti presso le strutture del circolo o presso strutture convenzionate.','club',1,6,'2025-10-07 15:53:58','2025-10-07 15:53:58',NULL),(7,'logistica_parcheggio','logistica','Parcheggio Gratuito','Il circolo mette a disposizione degli arbitri un parcheggio gratuito riservato nelle immediate vicinanze della club house. I posti auto riservati saranno segnalati.','club',1,10,'2025-10-07 15:53:58','2025-10-07 15:53:58',NULL),(8,'logistica_spogliatoio','logistica','Spogliatoio Dedicato','Il circolo fornirà uno spogliatoio dedicato agli arbitri con docce, armadietti e servizi igienici. Lo spogliatoio sarà disponibile da un\'ora prima dell\'inizio delle gare fino alla conclusione delle operazioni giornaliere.','club',1,11,'2025-10-07 15:53:58','2025-10-07 15:53:58',NULL),(9,'logistica_sala_riunioni','logistica','Sala Riunioni Disponibile','Il circolo mette a disposizione una sala riunioni per il briefing pre-gara e per eventuali riunioni degli arbitri. La sala sarà dotata di proiettore e lavagna per eventuali necessità organizzative.','club',1,12,'2025-10-07 15:53:58','2025-10-07 15:53:58',NULL),(10,'logistica_transfer','logistica','Servizio Transfer','Il circolo organizzerà un servizio transfer dalla stazione ferroviaria/aeroporto più vicina al circolo e ritorno. Gli arbitri dovranno comunicare gli orari di arrivo con almeno 48 ore di anticipo.','club',1,13,'2025-10-07 15:53:58','2025-10-07 15:53:58',NULL),(11,'resp_assicurazione_standard','responsabilita','Copertura Assicurativa Standard FIG','Gli arbitri sono coperti dalla polizza assicurativa standard della Federazione Italiana Golf per responsabilità civile e infortuni durante l\'espletamento delle funzioni arbitrali.','all',1,20,'2025-10-07 15:53:58','2025-10-07 15:53:58',NULL),(12,'resp_assicurazione_estesa','responsabilita','Copertura Assicurativa Estesa','Gli arbitri sono coperti da una polizza assicurativa estesa che comprende responsabilità civile, infortuni, assistenza sanitaria e tutela legale per tutta la durata della manifestazione, inclusi i trasferimenti da/per il circolo.','all',1,21,'2025-10-07 15:53:58','2025-10-07 15:53:58',NULL),(13,'resp_circolo_strutture','responsabilita','Responsabilità Circolo','Il circolo organizzatore si assume la piena responsabilità per eventuali danni alle strutture del circolo e per la sicurezza degli arbitri durante la permanenza presso le proprie installazioni.','club',1,22,'2025-10-07 15:53:58','2025-10-07 15:53:58',NULL),(14,'com_report_obbligatorio','comunicazioni','Report Post-Gara Obbligatorio','Gli arbitri sono tenuti a compilare e inviare il report post-gara entro 48 ore dalla conclusione della manifestazione utilizzando il modulo FIG standard. Il report dovrà essere inviato via email alla Segreteria Zonale di competenza.','referee',1,30,'2025-10-07 15:53:58','2025-10-07 15:53:58',NULL),(15,'com_referente_circolo','comunicazioni','Referente Circolo Sempre Disponibile','Il circolo garantisce la presenza di un referente sempre disponibile per gli arbitri durante tutta la durata della manifestazione. I recapiti del referente saranno comunicati al momento dell\'arrivo al circolo.','club',1,31,'2025-10-07 15:53:58','2025-10-07 15:53:58',NULL),(16,'com_gruppo_whatsapp','comunicazioni','Gruppo WhatsApp Dedicato','Sarà creato un gruppo WhatsApp dedicato alla manifestazione per facilitare le comunicazioni tra arbitri, circolo e Segreteria Zonale. Il gruppo sarà attivo da 48 ore prima dell\'inizio della manifestazione fino alla sua conclusione.','all',1,32,'2025-10-07 15:53:58','2025-10-07 15:53:58',NULL),(17,'com_briefing_obbligatorio','comunicazioni','Briefing Pre-Gara Obbligatorio','Gli arbitri sono tenuti a partecipare al briefing pre-gara che si terrà il giorno precedente l\'inizio della manifestazione. L\'orario e il luogo del briefing saranno comunicati via email almeno 3 giorni prima.','referee',1,33,'2025-10-07 15:53:58','2025-10-07 15:53:58',NULL),(18,'altro_dress_code','altro','Dress Code Arbitrale','Gli arbitri dovranno presentarsi in divisa ufficiale FIG (polo bianca con logo FIG, pantaloni blu scuro, scarpe da golf). Durante il briefing è richiesto abbigliamento business casual.','referee',1,40,'2025-10-07 15:53:58','2025-10-07 15:53:58',NULL),(19,'altro_orari_presenza','altro','Orari di Presenza','Gli arbitri dovranno presentarsi al circolo almeno 60 minuti prima dell\'orario di inizio previsto per la prima partenza. Al termine delle operazioni giornaliere, si richiede la permanenza fino alla chiusura dello scoring e alla firma dei cartellini.','referee',1,41,'2025-10-07 15:53:58','2025-10-07 15:53:58',NULL),(20,'altro_materiale_fornito','altro','Materiale Fornito dal Circolo','Il circolo fornirà agli arbitri tutto il materiale necessario per lo svolgimento delle funzioni: regolamento locale, scorecards, matite, ombrelli, acqua minerale e eventuale materiale di cancelleria necessario.','club',1,42,'2025-10-07 15:53:58','2025-10-07 15:53:58',NULL);
/*!40000 ALTER TABLE `notification_clauses` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `notifications`
--

DROP TABLE IF EXISTS `notifications`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `notifications` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `assignment_id` bigint unsigned DEFAULT NULL,
  `tournament_id` bigint unsigned DEFAULT NULL,
  `recipient_type` enum('referee','club','institutional') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `recipient_email` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `recipient_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `subject` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `body` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `template_used` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` enum('pending','sent','failed','cancelled') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
  `sent_at` timestamp NULL DEFAULT NULL,
  `scheduled_at` timestamp NULL DEFAULT NULL,
  `expires_at` timestamp NULL DEFAULT NULL,
  `error_message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `retry_count` int NOT NULL DEFAULT '0',
  `priority` int NOT NULL DEFAULT '0',
  `sender_id` bigint unsigned DEFAULT NULL,
  `attachments` json DEFAULT NULL,
  `metadata` json DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `notifications_sender_id_foreign` (`sender_id`),
  KEY `notifications_assignment_id_recipient_type_index` (`assignment_id`,`recipient_type`),
  KEY `notifications_status_created_at_index` (`status`,`created_at`),
  KEY `notifications_recipient_email_status_index` (`recipient_email`,`status`),
  KEY `notifications_tournament_id_recipient_type_index` (`tournament_id`,`recipient_type`),
  KEY `notifications_status_sent_at_index` (`status`,`sent_at`),
  CONSTRAINT `notifications_assignment_id_foreign` FOREIGN KEY (`assignment_id`) REFERENCES `assignments` (`id`) ON DELETE CASCADE,
  CONSTRAINT `notifications_sender_id_foreign` FOREIGN KEY (`sender_id`) REFERENCES `users` (`id`),
  CONSTRAINT `notifications_tournament_id_foreign` FOREIGN KEY (`tournament_id`) REFERENCES `tournaments` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=64 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

